  function contextObject(){const task=selectedTask(),campaign=selectedCampaign(),section=currentSection();return {user:{id:me().id||null,name:me().full_name||"Miembro",role:me().role_code||me().position||"member"},screen:section,task:task?{id:task.id,title:task.title,description:task.description,status:task.status,approval_status:task.approval_status,due_date:task.due_date,due_time:task.due_time,priority:task.priority,observation:task.observation||task.last_comment||task.comment||"",assignee:personName(task.assigned_to),campaign:nameOf(data().campaigns,task.campaign_id),client:nameOf(data().clients,task.client_id)}:null,campaign:campaign?{id:campaign.id,name:campaign.name,status:campaign.status,end_date:campaign.end_date,objective:campaign.objective}:null,counts:{my_open:myTasks().filter(t=>!done(t)&&!awaiting(t)).length,my_review:myTasks().filter(awaiting).length,pending_reviews:manager()?rows(data().tasks).filter(awaiting).length:0},timestamp:new Date().toISOString()}}
